#include <iostream>
#include <string>
using namespace std;

class Dog {
public:
    string name;
    string breed;

    Dog(string n, string b) : name(n), breed(b) {
        cout << name << " created!" << endl;
    }

    void bark() {
        cout << name << " says: Woof!" << endl;
    }

    string describe() {
        return name + " is a " + breed;
    }
};

int main() {
    Dog rex("Rex", "Labrador");
    Dog bella("Bella", "Poodle");

    rex.bark();
    bella.bark();
    cout << rex.describe() << endl;

    return 0;
}

instruction:
The destructor (`~ClassName()`) runs automatically when the object is destroyed.

This is the heart of RAII — the destructor releases resources:

```cpp
~Dog() {
    cout << name << " destroyed!" << endl;
}
```

No need to call it — C++ calls it for you.

