#include <iostream>
#include <string>
using namespace std;

class Resource {
public:
    string name;

    Resource(string n) : name(n) {
        cout << "Acquired: " << name << endl;
    }

    ~Resource() {
        cout << "Released: " << name << endl;
    }

    void use() {
        cout << "Using: " << name << endl;
    }
};

int main() {
    cout << "--- main start ---" << endl;
    {
        Resource r1("Database Connection");
        Resource r2("File Handle");
        r1.use();
        r2.use();
    }  // r2 destroyed first (LIFO!), then r1
    cout << "--- main end ---" << endl;

    return 0;
}

instruction:
Always use member initialiser lists instead of assignment in the constructor body:

```cpp
// Prefer this:
Person(string n, int a) : name(n), age(a) {}

// Over this:
Person(string n, int a) { name = n; age = a; }  // assigns AFTER default construction
```

For `const` members and references, initialisers are **required** — assignment won't work.

