#include <iostream>
#include <string>
using namespace std;

class BankAccount {
    const string owner;   // const — MUST use initializer list
    double balance;
    const int id;

public:
    BankAccount(string owner, double balance, int id)
        : owner(owner), balance(balance), id(id) {}

    void deposit(double amount) { balance += amount; }

    void print() {
        cout << "Account #" << id << " (" << owner << "): $" << balance << endl;
    }
};

int main() {
    BankAccount acc("Alice", 1000.0, 42);
    acc.deposit(500.0);
    acc.deposit(250.0);
    acc.print();

    return 0;
}

instruction:
Define operators for your types using `operator` keyword:

```cpp
Vector2D operator+(const Vector2D& other) const {
    return {x + other.x, y + other.y};
}
```

Overload `<<` for easy printing with cout.

starter:
#include <iostream>
#include <cmath>
using namespace std;

class Vector2D {
public:
    double x, y;
    Vector2D(double x=0, double y=0) : x(x), y(y) {}

    Vector2D operator+(const Vector2D& o) const { return {x+o.x, y+o.y}; }
    Vector2D operator*(double scalar)    const { return {x*scalar, y*scalar}; }
    double   dot(const Vector2D& o)      const { return x*o.x + y*o.y; }
    double   length()                    const { return sqrt(x*x + y*y); }
    bool     operator==(const Vector2D& o) const { return x==o.x && y==o.y; }

    friend ostream& operator<<(ostream& os, const Vector2D& v) {
        return os << "(" << v.x << ", " << v.y << ")";
    }
};

int main() {
    Vector2D a(3, 4), b(1, 2);
    cout << a + b      << endl;  // uses operator+
    cout << a * 2      << endl;  // uses operator*
    cout << a.length() << endl;  // 5.0
    cout << a.dot(b)   << endl;  // 11
    cout << boolalpha << (a == b) << endl;

    return 0;
}

instruction:
`this` is a pointer to the current object inside member functions. Use it when parameter names shadow member names:

```cpp
class Dog {
    string name;
public:
    Dog(string name) { this->name = name; }  // this->name = member
}
```

Or return `*this` for method chaining (fluent interface).

starter:
#include <iostream>
#include <string>
using namespace std;

class Builder {
    string result = "";

public:
    Builder& add(const string& text) {
        result += text;
        return *this;  // return reference to self for chaining
    }

    Builder& addLine(const string& text) {
        result += text + "\n";
        return *this;
    }

    string build() { return result; }
};

int main() {
    string text = Builder()
        .addLine("Line 1")
        .addLine("Line 2")
        .add("Line 3")
        .build();

    cout << text << endl;

    return 0;
}
